xpath.script:
//
window.ocEnableCounter = function(btn) {
    if (!btn || btn.disabled) return;
    btn.disabled = true;
    var orig = btn.innerHTML;
    btn.innerHTML = '<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="m14.5 12.5-8 8a2.119 2.119 0 0 1-3-3l8-8"/><path d="m16 16 6-6"/><path d="m8 8 6-6"/><path d="m9 7 8 8"/><path d="m21 11-8-8"/></svg> Active\u2026';
    fetch('/auction/owner/enable-counter', { method: 'POST' })
    .then(function(r) {
        if (!r.ok) throw new Error('server_error');
        return r.json();
    })
    .then(function(data) {
        if (!data.ok) {
            var msg = data.reason === 'write_error'
                ? '\u26a0\ufe0f Server error (check logs)'
                : '\u26a0\ufe0f No active tournament';
            btn.innerHTML = msg;
            setTimeout(function() {
                btn.disabled = false;
                btn.innerHTML = orig;
            }, 3000);
            return;
        }
        setTimeout(function() {
            btn.disabled = false;
            btn.innerHTML = orig;
        }, 4000);
    })
    .catch(function() {
        btn.disabled = false;
        btn.innerHTML = orig;
    });
};

document.addEventListener('DOMContentLoaded', function() {
    var fab = document.getElementById('oc-counter-fab');
    if (!fab) return;

    // Restore last saved position
    try {
        var saved = JSON.parse(localStorage.getItem('oc_counter_pos'));
        if (saved && typeof saved.left === 'number') {
            fab.style.left      = saved.left + 'px';
            fab.style.top       = saved.top  + 'px';
            fab.style.transform = 'none';
        }
    } catch(e) {}

    var dragging = false, moved = false;
    var startX, startY, origLeft, origTop;

    function startDrag(cx, cy) {
        var rect   = fab.getBoundingClientRect();
        origLeft   = rect.left;
        origTop    = rect.top;
        startX     = cx;
        startY     = cy;
        dragging   = true;
        moved      = false;
        fab.style.left      = origLeft + 'px';
        fab.style.top       = origTop  + 'px';
        fab.style.transform = 'none';
    }

    function doDrag(cx, cy) {
        if (!dragging) return;
        var dx = cx - startX, dy = cy - startY;
        if (Math.abs(dx) > 4 || Math.abs(dy) > 4) moved = true;
        fab.style.left = Math.max(0, Math.min(window.innerWidth  - fab.offsetWidth,  origLeft + dx)) + 'px';
        fab.style.top  = Math.max(0, Math.min(window.innerHeight - fab.offsetHeight, origTop  + dy)) + 'px';
    }

    function endDrag() {
        if (!dragging) return;
        dragging = false;
        if (moved) {
            try {
                localStorage.setItem('oc_counter_pos', JSON.stringify({
                    left: parseFloat(fab.style.left),
                    top:  parseFloat(fab.style.top)
                }));
            } catch(e) {}
        }
    }

    fab.addEventListener('mousedown',  function(e) { if (e.button === 0) { e.preventDefault(); startDrag(e.clientX, e.clientY); } });
    document.addEventListener('mousemove', function(e) { doDrag(e.clientX, e.clientY); });
    document.addEventListener('mouseup',   endDrag);

    fab.addEventListener('touchstart', function(e) { startDrag(e.touches[0].clientX, e.touches[0].clientY); }, { passive: true });
    document.addEventListener('touchmove', function(e) { if (dragging) doDrag(e.touches[0].clientX, e.touches[0].clientY); }, { passive: true });
    document.addEventListener('touchend', endDrag);

    // Suppress onclick when the interaction was a drag, not a tap
    fab.addEventListener('click', function(e) {
        if (moved) { e.stopImmediatePropagation(); moved = false; }
    }, true);
});
//
